#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static void controller_check_complete_level(controller_t *controller)
{
    /* Check if level dropped below complete threshold */
    if (controller->has_valid_level && 
        controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        if (controller->state != CONTROLLER_STATE_SAFE_IDLE &&
            controller->state != CONTROLLER_STATE_COMPLETE) {
            controller->filter_on = false;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_COMPLETE;
        }
    }
}

static void controller_transition_to_filtering(controller_t *controller, uint32_t now_ms)
{
    /* Transition to filtering when we have valid sensors and cloudy turbidity */
    if (controller->has_valid_turbidity && 
        controller->has_valid_level &&
        controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        controller->state = CONTROLLER_STATE_FILTERING;
        controller->filter_on = true;
        controller->drain_open = false;
        controller->clear_streak_count = 0;
    }
}

static void controller_process_turbidity_input(controller_t *controller, int turbidity_ntu, uint32_t now_ms)
{
    controller->has_valid_turbidity = true;
    controller->last_turbidity_ntu = turbidity_ntu;
    controller->last_turbidity_ms = now_ms;

    /* Check if we can transition from SAFE_IDLE to FILTERING */
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
        controller_transition_to_filtering(controller, now_ms);
        return;
    }

    switch (controller->state) {
    case CONTROLLER_STATE_FILTERING:
        if (turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            controller->clear_streak_count++;
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Enter settling state */
                controller->filter_on = false;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_SETTLING;
                controller->settling_started_ms = now_ms;
            }
        } else {
            /* Turbidity too high, reset streak but stay in filtering */
            controller->clear_streak_count = 0;
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        if (turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            /* Disturbance during settling - return to filtering */
            controller->filter_on = true;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->clear_streak_count = 0;
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        if (turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Disturbance during draining - close drain and restart filtering */
            controller->drain_open = false;
            controller->filter_on = true;
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->clear_streak_count = 0;
        }
        break;

    default:
        /* In SAFE_IDLE or COMPLETE, turbidity just refreshes freshness */
        break;
    }
}

static void controller_process_level_input(controller_t *controller, int level)
{
    controller->has_valid_level = true;
    controller->last_level = level;

    /* Check if we can transition from SAFE_IDLE to FILTERING */
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE &&
        controller->has_valid_turbidity) {
        controller_transition_to_filtering(controller, 0);
        return;
    }

    switch (controller->state) {
    case CONTROLLER_STATE_COMPLETE:
        /* If level rises above threshold, we can restart filtering */
        if (level >= CONTROLLER_MIN_PROCESS_LEVEL && controller->has_valid_turbidity) {
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
        }
        break;

    default:
        /* In other states, just update level freshness */
        break;
    }
}

static void controller_process_timeout(controller_t *controller)
{
    controller->has_valid_turbidity = false;
    controller->has_valid_level = false;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
    controller_set_safe_idle(controller);
}

static void controller_process_no_input(controller_t *controller, uint32_t now_ms)
{
    /* Check for sensor timeout - stale data forces safe state */
    bool turbidity_stale = (now_ms > controller->last_turbidity_ms + CONTROLLER_SENSOR_TIMEOUT_MS) &&
                           controller->has_valid_turbidity;
    bool level_stale = (now_ms > controller->last_level_ms + CONTROLLER_SENSOR_TIMEOUT_MS) &&
                       controller->has_valid_level;

    if ((controller->state != CONTROLLER_STATE_SAFE_IDLE && 
         controller->state != CONTROLLER_STATE_COMPLETE) &&
        (turbidity_stale || level_stale)) {
        controller_process_timeout(controller);
        return;
    }

    /* Check for complete level condition */
    controller_check_complete_level(controller);
}

static void controller_apply_actuator_commands(controller_t *controller, uint32_t now_ms)
{
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        controller->filter_on = false;
        controller->drain_open = false;
        break;

    case CONTROLLER_STATE_FILTERING:
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            /* Already handled by state transition, but ensure safety */
            controller->filter_on = false;
            controller->drain_open = false;
        } else if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->filter_on = true;
            controller->drain_open = false;
        }
        break;

    case CONTROLLER_STATE_SETTLING:
        controller->filter_on = false;
        controller->drain_open = false;

        /* Check if we can transition to draining */
        uint32_t settling_elapsed = 0U;
        if (now_ms >= controller->settling_started_ms) {
            settling_elapsed = now_ms - controller->settling_started_ms;
        } else {
            /* Wraparound protection - assume settled */
            settling_elapsed = CONTROLLER_SETTLING_MS;
        }

        if (settling_elapsed >= CONTROLLER_SETTLING_MS &&
            controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            controller->state = CONTROLLER_STATE_DRAINING;
            controller->drain_open = true;
        }

        /* Check if level dropped below threshold */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            controller->filter_on = false;
            controller->drain_open = false;
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        controller->drain_open = true;

        /* Check if level dropped below threshold */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            controller->filter_on = false;
            controller->drain_open = false;
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        controller->filter_on = false;
        controller->drain_open = false;
        break;
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller_process_turbidity_input(controller, input.turbidity_ntu, input.now_ms);
        break;

    case CONTROLLER_INPUT_LEVEL:
        controller_process_level_input(controller, input.level);
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        controller_process_timeout(controller);
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        controller_process_no_input(controller, input.now_ms);
        break;
    }

    /* Apply actuator commands based on current state */
    controller_apply_actuator_commands(controller, input.now_ms);

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) ||
                     (previous_drain_open != controller->drain_open) ||
                     (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

